def parse_log(log):
    log = log.split(',')
    result = ''
    for i in log:
        if i.startswith('close'):
            result += 'close, '
        elif i.startswith('sent'):
            result += 'bytes (' + i.split(' ')[1] + ') sent, '
        elif i.startswith('received'):
            result += 'bytes received, '
        elif i.startswith('lifetime'):
            result += 'lifetime'+ i.split(' ')[1]
